let t = context.get('t') || 0;
t += 1;
context.set('t', t);

let temperature = 78 + 4 * Math.sin(t / 8) + (Math.random() - 0.5) * 1.6;
let pressure = 2.0 + 0.15 * Math.sin(t / 10) + (Math.random() - 0.5) * 0.1;
let flow = 45 + 3 * Math.sin(t / 6) + (Math.random() - 0.5) * 1.8;
let level = 65 + 5 * Math.sin(t / 12) + (Math.random() - 0.5) * 2.4;
let power = 70 + 6 * Math.sin(t / 9) + (Math.random() - 0.5) * 3;
let vibration = Math.max(0, 1.5 + 0.2 * Math.sin(t / 5) + (Math.random() - 0.5) * 0.3);

power = Math.min(Math.max(power, 0), 100);

let energy = Math.max(
    0,
    4.0 + 0.08 * power + 0.03 * temperature + 0.60 * pressure - 0.015 * flow
);

let quality = 96
    - Math.abs(temperature - 78) * 0.75
    - Math.abs(pressure - 2.0) * 5.0
    - Math.abs(flow - 45) * 0.25
    - Math.max(0, vibration - 2.0) * 4.0;

quality = Math.min(Math.max(quality, 0), 100);

msg.topic = "factory/demo/tank01/telemetry";

msg.payload = {
    asset_id: "tank01",
    timestamp: new Date().toISOString(),
    temperature_c: Number(temperature.toFixed(2)),
    pressure_bar: Number(pressure.toFixed(2)),
    flow_lpm: Number(flow.toFixed(2)),
    level_pct: Number(level.toFixed(2)),
    heater_power_pct: Number(power.toFixed(2)),
    vibration_mm_s: Number(vibration.toFixed(2)),
    energy_kwh: Number(energy.toFixed(2)),
    product_quality_pct: Number(quality.toFixed(2))
};

return msg;
